"use client";

import { Children, isValidElement, useMemo, type ReactNode } from "react";
import {
  useCommandPaletteState,
  type CommandPaletteItemMetadata,
  type UseCommandPaletteStateOptions,
} from "./use-command-palette-state";
import { CommandPaletteContext } from "./command-palette-context";
import { CommandPaletteItem, type CommandPaletteItemProps } from "./command-palette-item";

export interface CommandPaletteProps extends Omit<UseCommandPaletteStateOptions, "items"> {
  children: ReactNode;
}

export function CommandPalette({
  children,
  ...stateProps
}: CommandPaletteProps) {
  const items = useMemo(() => collectCommandItems(children), [children]);
  const contextValue = useCommandPaletteState({ ...stateProps, items });

  return (
    <CommandPaletteContext value={contextValue}>
      {children}
    </CommandPaletteContext>
  );
}

function collectCommandItems(children: ReactNode): readonly CommandPaletteItemMetadata[] {
  const items: CommandPaletteItemMetadata[] = [];

  Children.forEach(children, (child) => {
    if (!isValidElement<{ children?: ReactNode }>(child)) return;

    if (child.type === CommandPaletteItem) {
      const props = child.props as CommandPaletteItemProps;
      items.push({
        id: props.id,
        value: props.value ?? props.id,
        disabled: props.disabled ?? false,
        onSelect: props.disabled ? undefined : props.onSelect,
      });
      return;
    }

    items.push(...collectCommandItems(child.props.children));
  });

  return items;
}

"use client";

import { createContext, useContext, type RefObject, type KeyboardEvent as ReactKeyboardEvent } from "react";

export interface CommandPaletteContextValue {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  previousFocusRef: RefObject<Element | null>;
  selectedId: string | null;
  onActivate: (id: string) => void;
  search: string;
  onSearchChange: (value: string) => void;
  shouldFilter: boolean;
  filter: (value: string, search: string) => boolean;
  itemCount: number;
  listId: string;
  listRef: RefObject<HTMLDivElement | null>;
  navKeyDown: (event: ReactKeyboardEvent) => void;
}

export const CommandPaletteContext = createContext<CommandPaletteContextValue | undefined>(undefined);

export function useCommandPaletteContext() {
  const context = useContext(CommandPaletteContext);
  if (!context) throw new Error("CommandPalette compound components must be used within a CommandPalette");
  return context;
}

"use client";

import { type ReactNode, useCallback, useRef, useState } from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { cn } from "@/lib/utils";
import { useCommandPaletteContext } from "./command-palette-context";
import { DialogShell } from "../shared/dialog-shell";
import { PortalContainerProvider } from "../shared/portal-context";

const contentVariants = cva(
  "border-2 border-border shadow-[0_0_40px_rgba(0,0,0,0.5)] bg-background relative flex flex-col max-h-[80vh] m-auto outline outline-1 outline-border/50 outline-offset-[1px] focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-foreground",
  {
    variants: {
      size: { sm: "max-w-sm", md: "max-w-xl", lg: "max-w-2xl" },
    },
    defaultVariants: { size: "md" },
  }
);

function getLiveText(search: string, itemCount: number): string {
  if (!search) return "";
  if (itemCount === 0) return "No results";
  return `${itemCount} result${itemCount === 1 ? "" : "s"} available`;
}

export interface CommandPaletteContentProps extends VariantProps<typeof contentVariants> {
  children: ReactNode;
  className?: string;
  label?: string;
}

export function CommandPaletteContent({ children, className, size, label = "Command palette" }: CommandPaletteContentProps) {
  const { open, onOpenChange, previousFocusRef, search, onSearchChange, itemCount } = useCommandPaletteContext();
  const dialogRef = useRef<HTMLDialogElement>(null);
  const [container, setContainer] = useState<Element | null>(null);

  const setDialogRef = useCallback((node: HTMLDialogElement | null) => {
    dialogRef.current = node;
    setContainer(node);
  }, []);

  const captureFocusBeforeOpen = useCallback(() => {
    if (!previousFocusRef.current && typeof document !== "undefined") {
      previousFocusRef.current = document.activeElement;
    }
  }, [previousFocusRef]);

  const focusSearchInput = useCallback(() => {
    dialogRef.current?.querySelector<HTMLElement>("[role='combobox']")?.focus();
  }, []);

  const restoreFocus = useCallback(() => {
    const el = previousFocusRef.current as HTMLElement | null;
    previousFocusRef.current = null;
    el?.focus?.();
  }, [previousFocusRef]);

  return (
    <DialogShell
      open={open}
      dialogRef={setDialogRef}
      onBeforeShowModal={captureFocusBeforeOpen}
      onAfterShowModal={focusSearchInput}
      onBackdropClick={() => onOpenChange(false)}
      onCancel={() => search ? onSearchChange("") : onOpenChange(false)}
      onClose={restoreFocus}
      className={cn(contentVariants({ size }), className)}
      aria-modal="true"
      aria-label={label}
    >
      <PortalContainerProvider container={container}>
        {children}
        <div role="status" aria-live="polite" aria-atomic="true" className="sr-only">
          {getLiveText(search, itemCount)}
        </div>
      </PortalContainerProvider>
    </DialogShell>
  );
}

